    },
    {
      "item": "target_value",
      "expected": "重疾险",
      "actual": null
    }
  ],
  "extra": [],
  "evidence": [
    {
      "source": "run_trace.extracted_output",
      "intent": "other",
      "confidence": 0.5,
      "target_value": null
